import { readdir, writeFile } from "node:fs/promises";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

const root = join(dirname(fileURLToPath(import.meta.url)), "..");
const uiDir = join(root, "src/shared/shadcn/ui");
const indexFile = join(root, "src/shared/shadcn/index.tsx");

const files = await readdir(uiDir);
const components = files
  .filter((file) => file.endsWith(".tsx"))
  .map((file) => file.replace(/\.tsx$/, ""))
  .sort((a, b) => a.localeCompare(b, undefined, { numeric: true, sensitivity: "base" }));

const content = [
  "// Generated by `npm run shadcn:exports` — do not edit manually.",
  "",
  ...components.map((name) => `export * from "./ui/${name}";`),
  "",
].join("\n");

await writeFile(indexFile, content);
console.log(`Updated ${indexFile} (${components.length} components)`);
